import { Racquet } from '../types';

export interface UserPreferences {
  playing_style: 'baseline' | 'allcourt' | 'serve_volley' | 'beginner';
  power_priority: number; // 1-10
  control_priority: number; // 1-10
  comfort_priority: number; // 1-10
  maneuverability_priority: number; // 1-10
  budget_range: [number, number]; // Price range if available
  experience_level: 'beginner' | 'intermediate' | 'advanced' | 'professional';
  preferred_weight_range?: [number, number];
  preferred_head_size_range?: [number, number];
}

export interface RecommendationScore {
  racquet: Racquet;
  similarity_score: number;
  explanation: string;
  strengths: string[];
  considerations: string[];
  alternative_for?: string;
}

export interface RecommendationResult {
  primary_recommendations: RecommendationScore[];
  alternative_recommendations: RecommendationScore[];
  budget_alternatives: RecommendationScore[];
}

function normalizeValue(value: number | undefined, min: number, max: number): number {
  if (value === undefined) return 0.5;
  return Math.max(0, Math.min(1, (value - min) / (max - min)));
}

function calculatePerformanceScore(
  racquet: Racquet,
  preferences: UserPreferences
): number {
  const weights = {
    power: preferences.power_priority / 10,
    control: preferences.control_priority / 10,
    comfort: preferences.comfort_priority / 10,
    maneuverability: preferences.maneuverability_priority / 10,
  };

  const performanceScores = {
    power: normalizeValue(racquet.power_avg, 1, 10),
    control: normalizeValue(racquet.control_avg, 1, 10),
    comfort: normalizeValue(racquet.comfort_avg, 1, 10),
    maneuverability: normalizeValue(racquet.maneuverability_avg, 1, 10),
  };

  return (
    performanceScores.power * weights.power +
    performanceScores.control * weights.control +
    performanceScores.comfort * weights.comfort +
    performanceScores.maneuverability * weights.maneuverability
  );
}

function calculatePhysicalScore(
  racquet: Racquet,
  preferences: UserPreferences
): number {
  let score = 0;
  let factors = 0;

  // Weight preference
  if (preferences.preferred_weight_range && racquet.weight_oz) {
    const [minWeight, maxWeight] = preferences.preferred_weight_range;
    if (racquet.weight_oz >= minWeight && racquet.weight_oz <= maxWeight) {
      score += 1;
    } else {
      const distanceFromRange = Math.min(
        Math.abs(racquet.weight_oz - minWeight),
        Math.abs(racquet.weight_oz - maxWeight)
      );
      score += Math.max(0, 1 - distanceFromRange / 2);
    }
    factors++;
  }

  // Head size preference
  if (preferences.preferred_head_size_range && racquet.head_size_sq_in) {
    const [minSize, maxSize] = preferences.preferred_head_size_range;
    if (racquet.head_size_sq_in >= minSize && racquet.head_size_sq_in <= maxSize) {
      score += 1;
    } else {
      const distanceFromRange = Math.min(
        Math.abs(racquet.head_size_sq_in - minSize),
        Math.abs(racquet.head_size_sq_in - maxSize)
      );
      score += Math.max(0, 1 - distanceFromRange / 20);
    }
    factors++;
  }

  return factors > 0 ? score / factors : 0.5;
}

function calculatePlayingStyleScore(
  racquet: Racquet,
  preferences: UserPreferences
): number {
  const style = preferences.playing_style;

  switch (style) {
    case 'baseline':
      return (
        normalizeValue(racquet.groundstrokes_avg, 1, 10) * 0.4 +
        normalizeValue(racquet.topspin_avg, 1, 10) * 0.3 +
        normalizeValue(racquet.power_avg, 1, 10) * 0.3
      );

    case 'allcourt':
      return (
        normalizeValue(racquet.overall_avg, 1, 10) * 0.3 +
        normalizeValue(racquet.maneuverability_avg, 1, 10) * 0.25 +
        normalizeValue(racquet.volleys_avg, 1, 10) * 0.25 +
        normalizeValue(racquet.groundstrokes_avg, 1, 10) * 0.2
      );

    case 'serve_volley':
      return (
        normalizeValue(racquet.serves_avg, 1, 10) * 0.4 +
        normalizeValue(racquet.volleys_avg, 1, 10) * 0.35 +
        normalizeValue(racquet.maneuverability_avg, 1, 10) * 0.25
      );

    case 'beginner':
      return (
        normalizeValue(racquet.comfort_avg, 1, 10) * 0.4 +
        normalizeValue(racquet.power_avg, 1, 10) * 0.3 +
        normalizeValue(racquet.maneuverability_avg, 1, 10) * 0.3
      );

    default:
      return 0.5;
  }
}

function generateExplanation(
  racquet: Racquet,
  preferences: UserPreferences,
  score: number
): string {
  const style = preferences.playing_style;
  const topPriority = Math.max(
    preferences.power_priority,
    preferences.control_priority,
    preferences.comfort_priority,
    preferences.maneuverability_priority
  );

  let explanation = `This racquet scores ${(score * 100).toFixed(0)}% match for your preferences. `;

  if (topPriority === preferences.power_priority) {
    explanation += `With a power rating of ${racquet.power_avg?.toFixed(1) || 'N/A'}, it aligns well with your power-focused game. `;
  } else if (topPriority === preferences.control_priority) {
    explanation += `Its control rating of ${racquet.control_avg?.toFixed(1) || 'N/A'} matches your precision-focused approach. `;
  } else if (topPriority === preferences.comfort_priority) {
    explanation += `The comfort rating of ${racquet.comfort_avg?.toFixed(1) || 'N/A'} suits your comfort-first priority. `;
  } else if (topPriority === preferences.maneuverability_priority) {
    explanation += `Its maneuverability score of ${racquet.maneuverability_avg?.toFixed(1) || 'N/A'} fits your agile playing style. `;
  }

  switch (style) {
    case 'baseline':
      explanation += `Perfect for baseline players with strong groundstrokes (${racquet.groundstrokes_avg?.toFixed(1) || 'N/A'}) and topspin (${racquet.topspin_avg?.toFixed(1) || 'N/A'}).`;
      break;
    case 'allcourt':
      explanation += `Ideal for all-court players with balanced performance across all shots.`;
      break;
    case 'serve_volley':
      explanation += `Great for serve-and-volley with excellent serves (${racquet.serves_avg?.toFixed(1) || 'N/A'}) and volleys (${racquet.volleys_avg?.toFixed(1) || 'N/A'}).`;
      break;
    case 'beginner':
      explanation += `Beginner-friendly with good comfort and power to help develop your game.`;
      break;
  }

  return explanation;
}

function generateStrengths(racquet: Racquet): string[] {
  const strengths: string[] = [];

  if (racquet.power_avg && racquet.power_avg >= 8) {
    strengths.push(`Excellent power (${racquet.power_avg.toFixed(1)})`);
  }
  if (racquet.control_avg && racquet.control_avg >= 8) {
    strengths.push(`Superior control (${racquet.control_avg.toFixed(1)})`);
  }
  if (racquet.comfort_avg && racquet.comfort_avg >= 8) {
    strengths.push(`High comfort (${racquet.comfort_avg.toFixed(1)})`);
  }
  if (racquet.maneuverability_avg && racquet.maneuverability_avg >= 8) {
    strengths.push(`Great maneuverability (${racquet.maneuverability_avg.toFixed(1)})`);
  }
  if (racquet.overall_avg && racquet.overall_avg >= 8) {
    strengths.push(`Outstanding overall rating (${racquet.overall_avg.toFixed(1)})`);
  }

  return strengths;
}

function generateConsiderations(racquet: Racquet, preferences: UserPreferences): string[] {
  const considerations: string[] = [];

  if (racquet.weight_oz) {
    if (racquet.weight_oz < 10) {
      considerations.push('Lighter weight - may need more swing speed for power');
    } else if (racquet.weight_oz > 12) {
      considerations.push('Heavier weight - may require more strength and stamina');
    }
  }

  if (racquet.head_size_sq_in) {
    if (racquet.head_size_sq_in < 95) {
      considerations.push('Smaller head size - requires more precision');
    } else if (racquet.head_size_sq_in > 105) {
      considerations.push('Larger head size - may sacrifice some control');
    }
  }

  if (preferences.experience_level === 'beginner' && racquet.control_avg && racquet.control_avg > 8) {
    considerations.push('High control racquet - may be challenging for beginners');
  }

  if (preferences.experience_level === 'professional' && racquet.power_avg && racquet.power_avg > 8) {
    considerations.push('High power racquet - advanced players may prefer more control');
  }

  return considerations;
}

export function calculateRacquetRecommendations(
  racquets: Racquet[],
  preferences: UserPreferences
): RecommendationResult {
  const scoredRacquets = racquets.map(racquet => {
    const performanceScore = calculatePerformanceScore(racquet, preferences);
    const physicalScore = calculatePhysicalScore(racquet, preferences);
    const playingStyleScore = calculatePlayingStyleScore(racquet, preferences);

    const overallScore = (performanceScore * 0.5) + (physicalScore * 0.25) + (playingStyleScore * 0.25);

    return {
      racquet,
      similarity_score: overallScore,
      explanation: generateExplanation(racquet, preferences, overallScore),
      strengths: generateStrengths(racquet),
      considerations: generateConsiderations(racquet, preferences),
    };
  });

  scoredRacquets.sort((a, b) => b.similarity_score - a.similarity_score);

  const primary_recommendations = scoredRacquets.slice(0, 5);
  const alternative_recommendations = scoredRacquets.slice(5, 10);

  // Budget alternatives (if we had price data)
  const budget_alternatives = scoredRacquets
    .filter(r => r.similarity_score > 0.6)
    .slice(0, 3)
    .map(r => ({
      ...r,
      alternative_for: 'budget-conscious players'
    }));

  return {
    primary_recommendations,
    alternative_recommendations,
    budget_alternatives,
  };
}

export function findSimilarRacquets(
  targetRacquet: Racquet,
  allRacquets: Racquet[],
  maxResults: number = 5
): RecommendationScore[] {
  return allRacquets
    .filter(r => r.id !== targetRacquet.id)
    .map(racquet => {
      let similarity = 0;
      let factors = 0;

      // Compare performance metrics
      const performanceMetrics = [
        'power_avg', 'control_avg', 'comfort_avg', 'maneuverability_avg',
        'stability_avg', 'serves_avg', 'returns_avg', 'groundstrokes_avg',
        'volleys_avg', 'slice_avg', 'topspin_avg', 'touch_feel_avg'
      ] as const;

      performanceMetrics.forEach(metric => {
        const target = targetRacquet[metric];
        const current = racquet[metric];
        if (target !== undefined && current !== undefined) {
          similarity += 1 - Math.abs(target - current) / 10;
          factors++;
        }
      });

      // Compare physical specs
      if (targetRacquet.weight_oz && racquet.weight_oz) {
        similarity += 1 - Math.abs(targetRacquet.weight_oz - racquet.weight_oz) / 5;
        factors++;
      }

      if (targetRacquet.head_size_sq_in && racquet.head_size_sq_in) {
        similarity += 1 - Math.abs(targetRacquet.head_size_sq_in - racquet.head_size_sq_in) / 30;
        factors++;
      }

      const finalScore = factors > 0 ? similarity / factors : 0;

      return {
        racquet,
        similarity_score: finalScore,
        explanation: `${(finalScore * 100).toFixed(0)}% similar to ${targetRacquet.brand} ${targetRacquet.model}`,
        strengths: generateStrengths(racquet),
        considerations: [`Similar alternative to ${targetRacquet.brand} ${targetRacquet.model}`],
      };
    })
    .sort((a, b) => b.similarity_score - a.similarity_score)
    .slice(0, maxResults);
}

