    explanation += `Its maneuverability score of ${racquet.maneuverability_avg?.toFixed(1) || 'N/A'} fits your agile playing style. `;
  }

  switch (style) {
    case 'baseline':
      explanation += `Perfect for baseline players with strong groundstrokes (${racquet.groundstrokes_avg?.toFixed(1) || 'N/A'}) and topspin (${racquet.topspin_avg?.toFixed(1) || 'N/A'}).`;
      break;
    case 'allcourt':
      explanation += `Ideal for all-court players with balanced performance across all shots.`;
      break;
    case 'serve_volley':
      explanation += `Great for serve-and-volley with excellent serves (${racquet.serves_avg?.toFixed(1) || 'N/A'}) and volleys (${racquet.volleys_avg?.toFixed(1) || 'N/A'}).`;
      break;
    case 'beginner':
      explanation += `Beginner-friendly with good comfort and power to help develop your game.`;
      break;
  }

  return explanation;
}

function generateStrengths(racquet: Racquet): string[] {
  const strengths: string[] = [];

  if (racquet.power_avg && racquet.power_avg >= 8) {
    strengths.push(`Excellent power (${racquet.power_avg.toFixed(1)})`);
  }
  if (racquet.control_avg && racquet.control_avg >= 8) {
    strengths.push(`Superior control (${racquet.control_avg.toFixed(1)})`);
  }
  if (racquet.comfort_avg && racquet.comfort_avg >= 8) {
    strengths.push(`High comfort (${racquet.comfort_avg.toFixed(1)})`);
  }
  if (racquet.maneuverability_avg && racquet.maneuverability_avg >= 8) {
    strengths.push(`Great maneuverability (${racquet.maneuverability_avg.toFixed(1)})`);
  }
  if (racquet.overall_avg && racquet.overall_avg >= 8) {
    strengths.push(`Outstanding overall rating (${racquet.overall_avg.toFixed(1)})`);
  }

  return strengths;
}

function generateConsiderations(racquet: Racquet, preferences: UserPreferences): string[] {
  const considerations: string[] = [];

  if (racquet.weight_oz) {
    if (racquet.weight_oz < 10) {
      considerations.push('Lighter weight - may need more swing speed for power');
    } else if (racquet.weight_oz > 12) {
      considerations.push('Heavier weight - may require more strength and stamina');
    }
  }

  if (racquet.head_size_sq_in) {
    if (racquet.head_size_sq_in < 95) {
      considerations.push('Smaller head size - requires more precision');
    } else if (racquet.head_size_sq_in > 105) {
      considerations.push('Larger head size - may sacrifice some control');
    }
  }

  if (preferences.experience_level === 'beginner' && racquet.control_avg && racquet.control_avg > 8) {
    considerations.push('High control racquet - may be challenging for beginners');
  }

  if (preferences.experience_level === 'professional' && racquet.power_avg && racquet.power_avg > 8) {
    considerations.push('High power racquet - advanced players may prefer more control');
  }

  return considerations;
}

export function calculateRacquetRecommendations(
  racquets: Racquet[],
  preferences: UserPreferences
): RecommendationResult {
  const scoredRacquets = racquets.map(racquet => {
    const performanceScore = calculatePerformanceScore(racquet, preferences);
    const physicalScore = calculatePhysicalScore(racquet, preferences);
    const playingStyleScore = calculatePlayingStyleScore(racquet, preferences);

    const overallScore = (performanceScore * 0.5) + (physicalScore * 0.25) + (playingStyleScore * 0.25);

    return {
      racquet,
      similarity_score: overallScore,
      explanation: generateExplanation(racquet, preferences, overallScore),
      strengths: generateStrengths(racquet),
      considerations: generateConsiderations(racquet, preferences),
    };
  });

  scoredRacquets.sort((a, b) => b.similarity_score - a.similarity_score);

  const primary_recommendations = scoredRacquets.slice(0, 5);
  const alternative_recommendations = scoredRacquets.slice(5, 10);

  // Budget alternatives (if we had price data)
  const budget_alternatives = scoredRacquets
    .filter(r => r.similarity_score > 0.6)
    .slice(0, 3)
    .map(r => ({
      ...r,
      alternative_for: 'budget-conscious players'
    }));

  return {
    primary_recommendations,
    alternative_recommendations,
    budget_alternatives,
  };
}

export function findSimilarRacquets(
  targetRacquet: Racquet,
  allRacquets: Racquet[],
  maxResults: number = 5
): RecommendationScore[] {
  return allRacquets
    .filter(r => r.id !== targetRacquet.id)
    .map(racquet => {
      let similarity = 0;
      let factors = 0;

      // Compare performance metrics
      const performanceMetrics = [
        'power_avg', 'control_avg', 'comfort_avg', 'maneuverability_avg',
        'stability_avg', 'serves_avg', 'returns_avg', 'groundstrokes_avg',
        'volleys_avg', 'slice_avg', 'topspin_avg', 'touch_feel_avg'
      ] as const;

      performanceMetrics.forEach(metric => {
        const target = targetRacquet[metric];
        const current = racquet[metric];
        if (target !== undefined && current !== undefined) {
          similarity += 1 - Math.abs(target - current) / 10;
          factors++;
        }
      });

      // Compare physical specs
      if (targetRacquet.weight_oz && racquet.weight_oz) {
        similarity += 1 - Math.abs(targetRacquet.weight_oz - racquet.weight_oz) / 5;
        factors++;
      }

      if (targetRacquet.head_size_sq_in && racquet.head_size_sq_in) {
        similarity += 1 - Math.abs(targetRacquet.head_size_sq_in - racquet.head_size_sq_in) / 30;
        factors++;
      }

      const finalScore = factors > 0 ? similarity / factors : 0;

      return {
        racquet,
        similarity_score: finalScore,
        explanation: `${(finalScore * 100).toFixed(0)}% similar to ${targetRacquet.brand} ${targetRacquet.model}`,
        strengths: generateStrengths(racquet),
        considerations: [`Similar alternative to ${targetRacquet.brand} ${targetRacquet.model}`],
      };
    })
    .sort((a, b) => b.similarity_score - a.similarity_score)
    .slice(0, maxResults);
}

