import { useState, useEffect, useCallback } from 'react';
import { Racquet } from '../types';
import { 
  UserPreferences, 
  RecommendationResult, 
  RecommendationScore,
  calculateRacquetRecommendations,
  findSimilarRacquets
} from '../utils/recommendation-algorithm';

interface RecommendationState {
  recommendations: RecommendationResult | null;
  similarRacquets: RecommendationScore[];
  isLoading: boolean;
  error: string | null;
  userPreferences: UserPreferences | null;
}

const DEFAULT_PREFERENCES: UserPreferences = {
  playing_style: 'allcourt',
  power_priority: 5,
  control_priority: 5,
  comfort_priority: 5,
  maneuverability_priority: 5,
  budget_range: [0, 1000],
  experience_level: 'intermediate',
};

export function useRecommendations(racquets: Racquet[]) {
  const [state, setState] = useState<RecommendationState>({
    recommendations: null,
    similarRacquets: [],
    isLoading: false,
    error: null,
    userPreferences: null,
  });

  const calculateRecommendations = useCallback(async (preferences: UserPreferences) => {
    if (!racquets.length) return;

    setState(prev => ({ ...prev, isLoading: true, error: null }));

    try {
      // Simulate API delay for better UX
      await new Promise(resolve => setTimeout(resolve, 500));

      const recommendations = calculateRacquetRecommendations(racquets, preferences);

      setState(prev => ({
        ...prev,
        recommendations,
        userPreferences: preferences,
        isLoading: false,
      }));
    } catch (error) {
      setState(prev => ({
        ...prev,
        error: error instanceof Error ? error.message : 'Failed to calculate recommendations',
        isLoading: false,
      }));
    }
  }, [racquets]);

  const findSimilar = useCallback((targetRacquet: Racquet, maxResults: number = 5) => {
    if (!racquets.length) return [];

    try {
      const similar = findSimilarRacquets(targetRacquet, racquets, maxResults);
      setState(prev => ({ ...prev, similarRacquets: similar }));
      return similar;
    } catch (error) {
      setState(prev => ({
        ...prev,
        error: error instanceof Error ? error.message : 'Failed to find similar racquets',
      }));
      return [];
    }
  }, [racquets]);

  const updatePreferences = useCallback((updates: Partial<UserPreferences>) => {
    setState(prev => {
      const newPreferences = prev.userPreferences 
        ? { ...prev.userPreferences, ...updates }
        : { ...DEFAULT_PREFERENCES, ...updates };

      return { ...prev, userPreferences: newPreferences };
    });
  }, []);

  const resetPreferences = useCallback(() => {
    setState(prev => ({ 
      ...prev, 
      userPreferences: DEFAULT_PREFERENCES,
      recommendations: null,
      error: null,
    }));
  }, []);

  const clearRecommendations = useCallback(() => {
    setState(prev => ({
      ...prev,
      recommendations: null,
      similarRacquets: [],
      error: null,
    }));
  }, []);

  // Auto-calculate recommendations when preferences change
  useEffect(() => {
    if (state.userPreferences && racquets.length > 0) {
      calculateRecommendations(state.userPreferences);
    }
  }, [state.userPreferences, racquets, calculateRecommendations]);

  return {
    // State
    recommendations: state.recommendations,
    similarRacquets: state.similarRacquets,
    isLoading: state.isLoading,
    error: state.error,
    userPreferences: state.userPreferences || DEFAULT_PREFERENCES,

    // Actions
    calculateRecommendations,
    findSimilar,
    updatePreferences,
    resetPreferences,
    clearRecommendations,

    // Computed values
    hasRecommendations: !!state.recommendations,
    hasSimilarRacquets: state.similarRacquets.length > 0,
  };
}

export type UseRecommendationsReturn = ReturnType<typeof useRecommendations>;

