'use client';

import React from 'react';
import { Card } from '../ui/Card';
import { Button } from '../ui/Button';
import { RecommendationScore } from '../../lib/utils/recommendation-algorithm';

interface RecommendationCardProps {
  recommendation: RecommendationScore;
  onCompare?: (racquet: any) => void;
  onViewDetails?: (racquet: any) => void;
  showAlternativeContext?: boolean;
}

export function RecommendationCard({
  recommendation,
  onCompare,
  onViewDetails,
  showAlternativeContext = false
}: RecommendationCardProps) {
  const { racquet, similarity_score, explanation, strengths, considerations } = recommendation;

  const getScoreColor = (score: number) => {
    if (score >= 0.8) return 'text-green-600';
    if (score >= 0.6) return 'text-yellow-600';
    return 'text-red-600';
  };

  const getScoreBackground = (score: number) => {
    if (score >= 0.8) return 'bg-green-100';
    if (score >= 0.6) return 'bg-yellow-100';
    return 'bg-red-100';
  };

  return (
    <Card className="p-6 space-y-4">
      {/* Header */}
      <div className="flex items-start justify-between">
        <div className="flex-1">
          <h3 className="text-lg font-semibold text-gray-900">
            {racquet.brand} {racquet.model}
          </h3>
          <p className="text-sm text-gray-600">
            {racquet.code}
          </p>
          {showAlternativeContext && recommendation.alternative_for && (
            <p className="text-xs text-blue-600 mt-1">
              Alternative for: {recommendation.alternative_for}
            </p>
          )}
        </div>

        <div className={`px-3 py-1 rounded-full text-sm font-medium ${getScoreBackground(similarity_score)}`}>
          <span className={getScoreColor(similarity_score)}>
            {Math.round(similarity_score * 100)}% Match
          </span>
        </div>
      </div>

      {/* Explanation */}
      <div className="text-sm text-gray-700">
        {explanation}
      </div>

      {/* Specifications */}
      <div className="grid grid-cols-2 gap-4 text-sm">
        <div>
          <span className="font-medium">Weight:</span> {racquet.weight || 'N/A'}
          {racquet.weight_oz && ` (${racquet.weight_oz.toFixed(1)} oz)`}
        </div>
        <div>
          <span className="font-medium">Head Size:</span> {racquet.head_size || 'N/A'}
          {racquet.head_size_sq_in && ` (${racquet.head_size_sq_in.toFixed(0)} sq in)`}
        </div>
        <div>
          <span className="font-medium">Power:</span> {racquet.power_avg?.toFixed(1) || 'N/A'}
        </div>
        <div>
          <span className="font-medium">Control:</span> {racquet.control_avg?.toFixed(1) || 'N/A'}
        </div>
      </div>

      {/* Performance Ratings */}
      <div className="space-y-2">
        <h4 className="font-medium text-sm text-gray-900">Performance Ratings</h4>
        <div className="grid grid-cols-2 gap-2 text-xs">
          {racquet.comfort_avg && (
            <div className="flex justify-between">
              <span>Comfort:</span>
              <span className="font-medium">{racquet.comfort_avg.toFixed(1)}</span>
            </div>
          )}
          {racquet.maneuverability_avg && (
            <div className="flex justify-between">
              <span>Maneuverability:</span>
              <span className="font-medium">{racquet.maneuverability_avg.toFixed(1)}</span>
            </div>
          )}
          {racquet.stability_avg && (
            <div className="flex justify-between">
              <span>Stability:</span>
              <span className="font-medium">{racquet.stability_avg.toFixed(1)}</span>
            </div>
          )}
          {racquet.overall_avg && (
            <div className="flex justify-between">
              <span>Overall:</span>
              <span className="font-medium">{racquet.overall_avg.toFixed(1)}</span>
            </div>
          )}
        </div>
      </div>

      {/* Strengths */}
      {strengths.length > 0 && (
        <div className="space-y-2">
          <h4 className="font-medium text-sm text-green-700">Strengths</h4>
          <ul className="text-xs text-green-600 space-y-1">
            {strengths.map((strength, index) => (
              <li key={index} className="flex items-start">
                <span className="text-green-500 mr-2">✓</span>
                {strength}
              </li>
            ))}
          </ul>
        </div>
      )}

      {/* Considerations */}
      {considerations.length > 0 && (
        <div className="space-y-2">
          <h4 className="font-medium text-sm text-amber-700">Considerations</h4>
          <ul className="text-xs text-amber-600 space-y-1">
            {considerations.map((consideration, index) => (
              <li key={index} className="flex items-start">
                <span className="text-amber-500 mr-2">!</span>
                {consideration}
              </li>
            ))}
          </ul>
        </div>
      )}

      {/* Actions */}
      <div className="flex gap-2 pt-2">
        {onCompare && (
          <Button
            variant="outline"
            size="sm"
            onClick={() => onCompare(racquet)}
            className="flex-1"
          >
            Compare
          </Button>
        )}
        {onViewDetails && (
          <Button
            variant="default"
            size="sm"
            onClick={() => onViewDetails(racquet)}
            className="flex-1"
          >
            View Details
          </Button>
        )}
      </div>

      {/* Review Count */}
      {racquet.review_count && (
        <div className="text-xs text-gray-500 text-center border-t pt-2">
          Based on {racquet.review_count} reviews
        </div>
      )}
    </Card>
  );
}

