        console.error('Error loading data:', error);
        // Fallback to local data
        try {
          const localData = await import('@/data/racquets.json');
          setRacquets(localData.default as RacquetData[]);
          const localBrands = await import('@/data/brands.json');
          setBrands(localBrands.default as Brand[]);
